      teachingPoints: [{cn: "\u4f53\u4f1a\u6df1\u60c5\u547c\u544a\u3001\u53cd\u590d\u7b49\u4fee\u8f9e\u624b\u6cd5\u7684\u8868\u8fbe\u6548\u679c", en: "Appreciate the effect of earnest address and repetition as rhetorical devices"}],
      parentTips: [{cn: "\u5f15\u5bfc\u5b69\u5b50\u4e86\u89e3\u5468\u603b\u7406\u7684\u4e8b\u8ff9\uff0c\u611f\u53d7\u8bd7\u4e2d\u7684\u601d\u5ff5\u4e4b\u60c5", en: "Help children learn about Premier Zhou\u2019s deeds and feel the longing expressed in the poem"}]
