        {term: "\u5a09\u5a77", meaning: {cn: "\u5f62\u5bb9\u5973\u5b50\u7684\u59ff\u6001\u7f8e\u3002", en: "Describing a woman\u2019s graceful bearing."}},
        {term: "\u51a0\u5195", meaning: {cn: "\u53e4\u4ee3\u5e1d\u738b\u3001\u5b98\u5458\u6234\u7684\u5e3d\u5b50\u3002", en: "A crown or ceremonial headdress worn by ancient emperors and officials."}}
