        {cn: "\u4f5c\u8005\u56e0\u81ea\u7136\u7684\u6fc0\u53d1\u800c\u751f\u51fa\u600e\u6837\u7684\u613f\u671b\uff1f", en: "What wish does the poet express, inspired by nature?"}
