      teachingPoints: [{cn: "\u4f53\u4f1a\u201c\u4e5f\u201d\u5b57\u7684\u4f7f\u7528\u4e0e\u8212\u7f13\u81ea\u5982\u7684\u6587\u98ce\uff0c\u7406\u89e3\u201c\u4e0e\u6c11\u540c\u4e50\u201d\u7684\u601d\u60f3", en: "Appreciate the use of \u2018ye\u2019 and the relaxed style; understand the concept of sharing joy with the people"}],
      parentTips: [{cn: "\u548c\u5b69\u5b50\u4e00\u8d77\u80cc\u8bf5\uff0c\u4f53\u4f1a\u6587\u7ae0\u8212\u7f13\u7684\u97f3\u97f5\u548c\u4e0e\u6c11\u540c\u4e50\u7684\u60c5\u6000", en: "Recite together and appreciate the essay\u2019s leisurely rhythm and spirit of sharing joy with the people"}]
