        {term: "\u6c89\u821f\u4fa7\u7554\u5343\u5e06\u8fc7", meaning: {cn: "\u6c89\u8239\u65c1\u8fb9\u5343\u5e06\u7ade\u53d1\uff0c\u6bd4\u55bb\u65b0\u4e8b\u7269\u5fc5\u7136\u53d6\u4ee3\u65e7\u4e8b\u7269\u3002", en: "A thousand sails pass the sunken ship \u2014 metaphor for the new inevitably replacing the old."}},
        {term: "\u4f46\u613f\u4eba\u957f\u4e45\uff0c\u5343\u91cc\u5171\u5a75\u5a1f", meaning: {cn: "\u5e0c\u671b\u4eba\u4eec\u90fd\u80fd\u5065\u5eb7\u957f\u5bff\uff0c\u5343\u91cc\u4e4b\u9694\u5171\u8d4f\u660e\u6708\u3002", en: "May all be blessed with long life, sharing the moon\u2019s beauty across a thousand miles."}}
