        {term: "\u4ed6\u4fe1\u529b", meaning: {cn: "\u4f5c\u8005\u4eff\u7167\u201c\u81ea\u4fe1\u529b\u201d\u65b0\u9020\u7684\u8bcd\uff0c\u6307\u76f8\u4fe1\u522b\u4eba\u800c\u4e0d\u76f8\u4fe1\u81ea\u5df1\u3002", en: "A word coined by the author after \u2018self-confidence,\u2019 meaning believing in others rather than oneself."}},
        {term: "\u4e2d\u56fd\u7684\u810a\u6881", meaning: {cn: "\u6bd4\u55bb\u4e2d\u56fd\u7684\u4e3b\u5fc3\u9aa8\uff0c\u6700\u575a\u5f3a\u7684\u652f\u67f1\u3002", en: "A metaphor for the backbone of China \u2014 its strongest pillars."}}
