      parentTips: [{cn: "\u548c\u5b69\u5b50\u8ba8\u8bba\u201c\u81ea\u4fe1\u201d\u7684\u542b\u4e49\uff0c\u601d\u8003\u5728\u5f53\u4eca\u65f6\u4ee3\u81ea\u4fe1\u529b\u7684\u8868\u73b0", en: "Discuss the meaning of \u2018self-confidence\u2019 with your child; reflect on how self-confidence manifests in the modern era"}]
